// Mimics transpiled CJS the way SDK packages ship it: the class is exposed
// through a getter-only property (in the exact shape cjs-module-lexer detects
// for named ESM imports), so patches must go through module.exports accessors.
'use strict'
class Client {
  async send(command) {
    return `sent:${command}`
  }
}
Object.defineProperty(exports, 'Client', {
  enumerable: true,
  get: function () {
    return Client
  },
})
